package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testGetEscapeCharacter() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Character expectedEscapeCharacter = null;

        // When
        Character actualEscapeCharacter = csvFormat.getEscapeCharacter();

        // Then
        assertEquals(expectedEscapeCharacter, actualEscapeCharacter);
    }
}
